 1→import BASE_URL from "../src/utils/apiBaseUrl";
 2→import apiRequest from "../src/utils/apiRequest";
 3→
 4→const authHeaders = (token, contentType) => {
 5→    const h = {};
 6→    if (contentType) h['Content-Type'] = contentType;
 7→    if (token) h['Authorization'] = `Bearer ${token}`;
 8→    return h;
 9→};
10→
11→const parseJsonError = async (response, fallback) => {
12→    const body = await response.json().catch(() => ({}));
13→    return body?.error || (typeof body === 'string' ? body : null) || fallback;
14→};
15→
16→/**
17→ * Public GET request (no auth). Returns parsed JSON.
18→ */
19→export const publicGet = async (path, fallback = 'request failed') => {
20→    const response = await apiRequest(`${BASE_URL}${path}`, { method: 'GET' });
21→    if (!response.ok) throw new Error(await parseJsonError(response, fallback));
22→    return response.json();
23→};
24→
25→/**
26→ * Authed GET request (bearer token). Returns parsed JSON.
27→ */
28→export const authedGet = async (token, path, fallback = 'request failed') => {
29→    const response = await apiRequest(`${BASE_URL}${path}`, {
30→        method: 'GET',
31→        headers: authHeaders(token),
32→    });
33→    if (!response.ok) throw new Error(await parseJsonError(response, fallback));
34→    return response.json();
35→};
36→
37→/**
38→ * Authed JSON body request. Stringifies body. Returns parsed JSON.
39→ */
40→export const authedJsonRequest = async (token, method, path, body, fallback = 'request failed') => {
41→    const response = await apiRequest(`${BASE_URL}${path}`, {
42→        method,
43→        headers: authHeaders(token, 'application/json'),
44→        body: body != null ? JSON.stringify(body) : undefined,
45→    });
46→    if (!response.ok) throw new Error(await parseJsonError(response, fallback));
47→    return response.json();
48→};
49→
50→/**
51→ * Authed FormData/body request (no Content-Type — browser sets it for FormData). Returns parsed JSON.
52→ */
53→export const authedFormRequest = async (token, method, path, body, fallback = 'request failed') => {
54→    const response = await apiRequest(`${BASE_URL}${path}`, {
55→        method,
56→        headers: authHeaders(token),
57→        body,
58→    });
59→    if (!response.ok) throw new Error(await parseJsonError(response, fallback));
60→    return response.json();
61→};
62→
63→export { BASE_URL, apiRequest };
64→

