 715→        // ── Circular avatar ──
 716→        let avatarComposite = null;
 717→        const avatarSize = 180;
 718→        const avatarUrl = user.image_url;
 719→        if (avatarUrl) {
 720→            const avatarEval = evaluateShareImageCandidate(avatarUrl);
 721→            if (avatarEval.ok && avatarEval.resolvedUrl) {
 722→                try {
 723→                    const remote = await fetchRemoteImageBuffer(avatarEval.resolvedUrl);
 724→                    const circleMask = Buffer.from(
 725→                        `<svg width="${avatarSize}" height="${avatarSize}">
 726→                            <circle cx="${avatarSize / 2}" cy="${avatarSize / 2}" r="${avatarSize / 2}" fill="white"/>
 727→                        </svg>`
 728→                    );
 729→                    const resizedAvatar = await sharp(remote.buffer, { limitInputPixels: 60_000_000 })
 730→                        .resize(avatarSize, avatarSize, { fit: 'cover' })
 731→                        .png()
 732→                        .toBuffer();
 733→                    const circularAvatar = await sharp(resizedAvatar)
 734→                        .composite([{ input: circleMask, blend: 'dest-in' }])
 735→                        .png()
 736→                        .toBuffer();
 737→                    avatarComposite = circularAvatar;
 738→                } catch { /* skip avatar */ }
 739→            }
 740→        }
 741→
 742→        // ── Compose all layers ──
 743→        const composites = [
 744→            { input: overlayBuffer, top: 0, left: 0 },
 745→        ];
 746→
 747→        if (avatarComposite) {
 748→            const avatarLeft = Math.round((DEFAULT_OG_IMAGE_WIDTH - avatarSize) / 2);
 749→            composites.push({ input: avatarComposite, top: 100, left: avatarLeft });
 750→        }
 751→
 752→        const finalImage = await sharp(baseLayer)
 753→            .composite(composites)
 754→            .jpeg({ quality: 82, mozjpeg: true })
 755→            .toBuffer();
 756→
 757→        setShareImageCached(`profile:${username}`, finalImage);
 758→        res.set('Content-Type', 'image/jpeg');
 759→        res.set('Cache-Control', 'public, max-age=3600');
 760→        return res.send(finalImage);
 761→    } catch (err) {
 762→        console.error('profile share image route error:', err?.message || err);
 763→        return res.redirect(302, DEFAULT_OG_IMAGE_URL);
 764→    }
 765→});
