 859→    };
 860→
 861→    const fallbackWithReason = (reason) => {
 862→        debugPayload.ok = false;
 863→        debugPayload.fallback = true;
 864→        debugPayload.stage = 'fallback';
 865→        debugPayload.reason = reason;
 866→        if (debugMode) {
