    authedGet(token, `/analytics?range=${encodeURIComponent(range)}`, 'failed to fetch analytics');
```

Follows the exact pattern of `getWeeklyRecap`.

---

### 5. Frontend: Component Tree and Data Flow

**Directory:** `C:\Users\johnm\iskrib_v3\client\src\components\Analytics\`

```
Analytics/
  AnalyticsDashboard.jsx     -- Main page component (route target)
  AnalyticsDashboard.css     -- All styles for the dashboard
  AnalyticsSummary.jsx       -- Top row: 4 StatTile-like summary cards
  TimeRangeSelector.jsx      -- 7d / 30d / 90d / All toggle
  ViewsChart.jsx             -- Recharts AreaChart for views over time
  ReactionsChart.jsx         -- Recharts AreaChart for reactions over time
  ReactionBreakdown.jsx      -- Horizontal bar chart or pie for reaction types
  TopPosts.jsx               -- Ranked list of top-performing posts (clickable)
  PublishingFrequency.jsx    -- Bar chart showing posts per week
  useAnalyticsData.js        -- Custom hook wrapping React Query
```

#### 5A. Data Flow Hook: `useAnalyticsData.js`

```javascript
import { useQuery } from '@tanstack/react-query';
import { getWriterAnalytics } from '../../../API/Api';

const useAnalyticsData = (token, userId, range) => {
    return useQuery({
        queryKey: ['writerAnalytics', userId, range],
        queryFn: () => getWriterAnalytics(token, range),
        enabled: !!token && !!userId,
        staleTime: 1000 * 60 * 5,   // 5 minutes
        refetchOnWindowFocus: false,
    });
};

export default useAnalyticsData;
```

**Pattern match:** Query key uses `userId` (not `access_token`) to prevent cache bust on token rotation, matching the established convention from MEMORY.md. `staleTime` of 5 minutes matches QueryClient defaults.

#### 5B. Main Dashboard Component: `AnalyticsDashboard.jsx`

```jsx
import React, { useState } from 'react';
import { motion } from 'framer-motion';
import { useAuth } from '../../Context/useAuth';
import useAnalyticsData from './useAnalyticsData';
import TimeRangeSelector from './TimeRangeSelector';
import AnalyticsSummary from './AnalyticsSummary';
import ViewsChart from './ViewsChart';
import ReactionsChart from './ReactionsChart';
import ReactionBreakdown from './ReactionBreakdown';
import TopPosts from './TopPosts';
import PublishingFrequency from './PublishingFrequency';
import { BeatLoader } from 'react-spinners';
import './AnalyticsDashboard.css';

const AnalyticsDashboard = () => {
    const { session, user } = useAuth();
    const token = session?.access_token;
    const userId = user?.userData?.[0]?.id;

    const [range, setRange] = useState('30d');

    const { data, isLoading } = useAnalyticsData(token, userId, range);
    const analytics = data?.analytics;

    if (isLoading) {
        return (
            <div className="analytics-dashboard">
                <div className="analytics-loading">
                    <BeatLoader size={10} color="var(--text-muted)" />
                </div>
            </div>
        );
    }

    if (!analytics) {
        return (
            <div className="analytics-dashboard">
                <div className="analytics-empty">
                    <p>Start publishing to see your analytics here.</p>
                </div>
            </div>
        );
    }

    return (
        <motion.div
            className="analytics-dashboard"
            initial={{ opacity: 0, y: 10 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.35, ease: 'easeOut' }}
        >
            <div className="analytics-header">
                <h2 className="analytics-title">Analytics</h2>
                <TimeRangeSelector value={range} onChange={setRange} />
