            <AnalyticsSummary summary={analytics.summary} streak={analytics.streak} />

            <div className="analytics-charts-grid">
                <ViewsChart data={analytics.views_series} range={range} />
                <ReactionsChart data={analytics.reactions_series} range={range} />
            </div>

            <div className="analytics-bottom-grid">
                <ReactionBreakdown data={analytics.reaction_breakdown} />
                <PublishingFrequency data={analytics.publishing_frequency} />
            </div>

            <TopPosts posts={analytics.top_posts} />
        </motion.div>
    );
};

export default AnalyticsDashboard;
```

#### 5C. TimeRangeSelector Component

A row of pill-style buttons matching the existing design system:

