                    <defs>
                        <linearGradient id="viewsGradient" x1="0" y1="0" x2="0" y2="1">
                            <stop offset="5%" stopColor="var(--accent-amber)" stopOpacity={0.3} />
                            <stop offset="95%" stopColor="var(--accent-amber)" stopOpacity={0} />
