    text-transform: uppercase;
    letter-spacing: 0.3px;
    color: var(--text-secondary);
    margin: 0 0 16px;
}

/* ─── Charts Grid ─── */
.analytics-charts-grid {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 16px;
}

.analytics-bottom-grid {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 16px;
}

/* ─── Summary Tiles ─── */
/* Reuses .recap-tile pattern */
.analytics-summary-grid {
    display: grid;
    grid-template-columns: repeat(4, 1fr);
    gap: 10px;
}

/* ─── Top Posts ─── */
.analytics-top-post-row {
    display: flex;
    align-items: center;
    gap: 14px;
    padding: 14px 16px;
    border-radius: 10px;
    cursor: pointer;
    transition: background 0.15s ease;
}

.analytics-top-post-row:hover {
    background: var(--bg-hover);
}

/* ─── Mobile ─── */
@media (max-width: 480px) {
    .analytics-charts-grid,
    .analytics-bottom-grid {
        grid-template-columns: 1fr;
    }

    .analytics-summary-grid {
        grid-template-columns: repeat(2, 1fr);
    }

    .analytics-range-btn {
        padding: 5px 10px;
        font-size: 11px;
    }
}

/* ─── Dark Mode ─── */
[data-theme="dark"] .analytics-range-btn.is-active {
    background: var(--bg-card);
    box-shadow: var(--shadow-card-sm);
}
```

**Recharts theme integration:** Recharts SVG elements accept CSS variable values via inline props (`stroke="var(--accent-amber)"`). For the custom tooltip, a small React component applies the existing card styles (`var(--bg-card)`, `var(--border-card)`, `var(--shadow-card)`).

